     1→import React, { useEffect, useState } from "react";
     2→import {
     3→  View,
     4→  Text,
     5→  StyleSheet,
     6→  ActivityIndicator,
     7→  TouchableOpacity,
     8→  useWindowDimensions,
     9→} from "react-native";
    10→import { useHeaderHeight } from "@react-navigation/elements";
    11→import type { StackScreenProps } from "@react-navigation/stack";
    12→import type { RootStackParamList } from "../../App";
    13→import { fetchSession, fetchSessionEvents, fetchSessionOverview, fetchSessionCheckpoints, type Session, type Event, type InteractionOverview, type SessionCheckpoint } from "../api";
    14→import { EventItem } from "../components/EventItem";
    15→import { ToolGroupItem, type ToolUseData } from "../components/ToolGroupItem";
    16→
    17→type Props = StackScreenProps<RootStackParamList, "SessionDetail">;
    18→
    19→// ─── Event grouping ───────────────────────────────────────────────────────────
    20→
    21→type DisplayItem =
    22→  | { kind: "event"; event: Event }
    23→  | { kind: "toolGroup"; tools: ToolUseData[] }
    24→  | { kind: "checkpoint"; checkpoint: SessionCheckpoint };
    25→
    26→function groupEvents(events: Event[]): DisplayItem[] {
    27→  // Pass 1: pair PreToolUse with its matching PostToolUse
    28→  const postMap = new Map<string, Event>();
    29→  for (const event of events) {
    30→    if (event.event === "PostToolUse" || event.event === "PostToolUseFailure") {
    31→      const d = event.data as Record<string, unknown>;
    32→      const id = typeof d.tool_use_id === "string" ? d.tool_use_id : null;
    33→      if (id) postMap.set(id, event);
    34→    }
    35→  }
    36→
    37→  type RawItem =
    38→    | { kind: "event"; event: Event }
    39→    | { kind: "toolUse"; pre: Event; post?: Event; failed: boolean };
    40→
    41→  const raw: RawItem[] = [];
    42→  const consumed = new Set<number>();
    43→
    44→  for (const event of events) {
    45→    if (
    46→      (event.event === "PostToolUse" || event.event === "PostToolUseFailure") &&
    47→      consumed.has(event.id)
    48→    ) {
    49→      continue;
    50→    }
    51→    if (event.event === "PreToolUse") {
    52→      const d = event.data as Record<string, unknown>;
    53→      const toolUseId = typeof d.tool_use_id === "string" ? d.tool_use_id : null;
    54→      const post = toolUseId ? postMap.get(toolUseId) : undefined;
    55→      if (post) consumed.add(post.id);
    56→      raw.push({ kind: "toolUse", pre: event, post, failed: post?.event === "PostToolUseFailure" });
    57→      continue;
    58→    }
    59→    raw.push({ kind: "event", event });
    60→  }
    61→
    62→  // Pass 2: collapse consecutive toolUse + Notification items into toolGroup.
    63→  // Notifications are absorbed silently (they're mostly "permission needed" noise).
    64→  const isGroupable = (item: RawItem) =>
    65→    item.kind === "toolUse" ||
    66→    (item.kind === "event" && item.event.event === "Notification");
    67→
    68→  const result: DisplayItem[] = [];
    69→  let i = 0;
    70→  while (i < raw.length) {
    71→    if (isGroupable(raw[i])) {
    72→      const group: ToolUseData[] = [];
    73→      while (i < raw.length && isGroupable(raw[i])) {
    74→        const item = raw[i];
    75→        if (item.kind === "toolUse") {
    76→          group.push({ pre: item.pre, post: item.post, failed: item.failed });
    77→        }
    78→        // Notifications are swallowed — don't add to group
    79→        i++;
    80→      }
    81→      if (group.length > 0) {
    82→        result.push({ kind: "toolGroup", tools: group });
    83→      }
    84→      // If the run was notifications-only, they're silently dropped
    85→    } else {
    86→      result.push({ kind: "event", event: (raw[i] as { kind: "event"; event: Event }).event });
    87→      i++;
    88→    }
    89→  }
    90→
    91→  return result;
    92→}
    93→
    94→// ─── Checkpoint row ───────────────────────────────────────────────────────────
    95→
    96→function CheckpointRow({
    97→  checkpoint,
    98→  onPress,
    99→}: {
   100→  checkpoint: SessionCheckpoint;
   101→  onPress: () => void;
   102→}) {
   103→  const [expanded, setExpanded] = useState(false);
   104→  const outTokens = checkpoint.tokenUsage?.outputTokens ?? 0;
   105→  const fileCount = checkpoint.filesTouched.length;
   106→  const s = checkpoint.summary;
   107→
   108→  return (
   109→    <View style={styles.cpWrapper}>
   110→      <TouchableOpacity onPress={() => setExpanded((v) => !v)} style={styles.cpRow}>
   111→        <View style={styles.cpBody}>
   112→          <View style={styles.cpTop}>
   113→            <Text style={styles.cpLabel}>Checkpoint</Text>
   114→            <Text style={styles.cpId}>{checkpoint.checkpointId}</Text>
   115→            {checkpoint.branch && (
   116→              <Text style={styles.cpBranch}>{checkpoint.branch}</Text>
   117→            )}
   118→          </View>
   119→          {s?.intent ? (
   120→            <Text style={styles.cpIntent} numberOfLines={expanded ? undefined : 1}>
   121→              {s.intent}
   122→            </Text>
   123→          ) : null}
   124→        </View>
   125→        <View style={styles.cpMeta}>
   126→          {fileCount > 0 && (
   127→            <Text style={styles.cpMetaText}>{fileCount} file{fileCount !== 1 ? "s" : ""}</Text>
   128→          )}
   129→          {outTokens > 0 && (
   130→            <Text style={styles.cpMetaText}>{outTokens.toLocaleString()} tok</Text>
   131→          )}
   132→        </View>
   133→      </TouchableOpacity>
   134→
   135→      {expanded && (
   136→        <View style={styles.cpDropdown}>
   137→          {s?.outcome ? (
   138→            <View style={styles.cpSection}>
   139→              <Text style={styles.cpSectionLabel}>✓ Outcome</Text>
   140→              <Text style={styles.cpSectionText} selectable>{s.outcome}</Text>
   141→            </View>
   142→          ) : null}
   143→          {s?.repoLearnings && s.repoLearnings.length > 0 ? (
   144→            <View style={styles.cpSection}>
   145→              <Text style={styles.cpSectionLabel}>◎ Repo learnings</Text>
   146→              {s.repoLearnings.map((item, i) => (
   147→                <Text key={i} style={styles.cpBullet} selectable>· {item}</Text>
   148→              ))}
   149→            </View>
   150→          ) : null}
   151→          {s?.codeLearnings && s.codeLearnings.length > 0 ? (
   152→            <View style={styles.cpSection}>
   153→              <Text style={styles.cpSectionLabel}>{"</>"} Code learnings</Text>
