   227→
   228→        // Merge events and checkpoints in chronological order
   229→        const grouped = groupEvents(evs);
   230→        const merged: DisplayItem[] = [];
   231→        let cpIdx = 0;
   232→        const sortedCps = [...checkpoints].sort((a, b) => {
   233→          const ta = a.createdAt ?? "";
   234→          const tb = b.createdAt ?? "";
   235→          return ta < tb ? -1 : ta > tb ? 1 : 0;
